import { FastifyRequest, FastifyReply, FastifyError } from 'fastify';
import { BaseError } from '../errors/base.error.js';
import { ZodError } from 'zod';
import { Prisma } from '@prisma/client';
import { getMetricsService } from '../services/observability/metrics.service.js';
import { getTracingService } from '../services/observability/tracing.service.js';

const metricsService = getMetricsService();
const tracingService = getTracingService();

export async function globalErrorHandler(
  error: Error | FastifyError | BaseError,
  request: FastifyRequest,
  reply: FastifyReply
) {
  // Log error to observability
  const route = request.routerPath || request.url;
  metricsService.recordError(error.name, route);
  tracingService.addEvent('error', {
    'error.type': error.name,
    'error.message': error.message,
    'error.stack': error.stack
  });

  // Handle BaseError (custom errors)
  if (error instanceof BaseError) {
    return reply.code(error.statusCode).send(error.toJSON());
  }

  // Handle Zod validation errors
  if (error instanceof ZodError) {
    const validationErrors = error.errors.map(err => ({
      field: err.path.join('.'),
      message: err.message,
      code: err.code
    }));
    return reply.code(400).send({
      code: 'VALIDATION_ERROR',
      message: 'Request validation failed',
      statusCode: 400,
      details: { errors: validationErrors },
      timestamp: new Date().toISOString()
    });
  }

  // Handle Prisma errors
  if (error instanceof Prisma.PrismaClientKnownRequestError) {
    return handlePrismaError(error, reply);
  }

  // Handle Fastify errors
  if ('statusCode' in error && error.statusCode) {
    return reply.code(error.statusCode).send({
      code: 'FASTIFY_ERROR',
      message: error.message,
      statusCode: error.statusCode,
      timestamp: new Date().toISOString()
    });
  }

  // Unknown errors - log and return generic message
  request.log.error({
    err: error,
    request: {
      method: request.method,
      url: request.url,
      headers: request.headers,
      body: request.body
    }
  }, 'Unhandled error occurred');

  return reply.code(500).send({
    code: 'INTERNAL_SERVER_ERROR',
    message: process.env.NODE_ENV === 'production'
      ? 'An unexpected error occurred'
      : error.message,
    statusCode: 500,
    timestamp: new Date().toISOString()
  });
}

function handlePrismaError(
  error: Prisma.PrismaClientKnownRequestError,
  reply: FastifyReply
) {
  switch (error.code) {
    case 'P2002': // Unique constraint violation
      return reply.code(409).send({
        code: 'CONFLICT',
        message: 'A record with this value already exists',
        statusCode: 409,
        details: { field: error.meta?.target },
        timestamp: new Date().toISOString()
      });
    case 'P2025': // Record not found
      return reply.code(404).send({
        code: 'NOT_FOUND',
        message: 'Record not found',
        statusCode: 404,
        timestamp: new Date().toISOString()
      });
    case 'P2003': // Foreign key constraint failed
      return reply.code(400).send({
        code: 'INVALID_REFERENCE',
        message: 'Referenced record does not exist',
        statusCode: 400,
        details: { field: error.meta?.field_name },
        timestamp: new Date().toISOString()
      });
    default:
      return reply.code(500).send({
        code: 'DATABASE_ERROR',
        message: 'Database operation failed',
        statusCode: 500,
        timestamp: new Date().toISOString()
      });
  }
}

