import { OpenAI } from 'openai';
import { CircuitBreaker } from '../../utils/circuit-breaker.js';
import { OpenAIError } from '../../errors/external.errors.js';
import { getMetricsService } from '../observability/metrics.service.js';

export class ResilientOpenAIService {
  private openai: OpenAI;
  private embeddingBreaker: CircuitBreaker<any[], any>;
  private chatBreaker: CircuitBreaker<any[], any>;
  private metrics = getMetricsService();

  constructor() {
    this.openai = new OpenAI({
      apiKey: process.env.OPENAI_API_KEY,
      timeout: 30000,
      maxRetries: 2
    });

    // Circuit breaker for embeddings
    this.embeddingBreaker = new CircuitBreaker(
      this.generateEmbeddingInternal.bind(this),
      {
        failureThreshold: 5,
        successThreshold: 2,
        timeout: 60000,
        monitoringPeriod: 120000
      },
      this.embeddingFallback.bind(this)
    );

    // Circuit breaker for chat completions
    this.chatBreaker = new CircuitBreaker(
      this.generateChatInternal.bind(this),
      {
        failureThreshold: 3,
        successThreshold: 2,
        timeout: 90000,
        monitoringPeriod: 180000
      }
    );
  }

  async generateEmbedding(text: string): Promise<number[]> {
    try {
      return await this.embeddingBreaker.execute(text);
    } catch (error: any) {
      this.metrics.recordError('OpenAI', 'embedding');
      throw new OpenAIError('Embedding generation failed', {
        circuitState: this.embeddingBreaker.getState(),
        originalError: error.message
      });
    }
  }

  private async generateEmbeddingInternal(text: string): Promise<number[]> {
    const response = await this.openai.embeddings.create({
      model: 'text-embedding-3-small',
      input: text
    });
    return response.data[0].embedding;
  }

  private async embeddingFallback(text: string): Promise<number[]> {
    // Return cached embedding or default vector
    console.warn('Using embedding fallback for:', text.substring(0, 50));
    return new Array(1536).fill(0);
  }

  getCircuitStats() {
    return {
      embedding: this.embeddingBreaker.getStats(),
      chat: this.chatBreaker.getStats()
    };
  }
}

codePatterns.versionMiddleware:
import { FastifyRequest, FastifyReply } from 'fastify';

export interface ApiVersion {
  major: number;
  minor: number;
  patch?: number;
}

export function parseApiVersion(version: string): ApiVersion | null {
  const match = version.match(/^v?(\d+)\.(\d+)(?:\.(\d+))?$/);
  if (!match) return null;

  return {
    major: parseInt(match[1]),
    minor: parseInt(match[2]),
    patch: match[3] ? parseInt(match[3]) : undefined
  };
}

export function apiVersionMiddleware(
  request: FastifyRequest,
  reply: FastifyReply
) {
  // Extract version from URL path (/api/v1/...) or header
  const pathVersion = request.url.match(/\/api\/(v\d+)\//)?.[1];
  const headerVersion = request.headers['api-version'] as string;

  const version = pathVersion || headerVersion || 'v1';

  // Add version to request context
  (request as any).apiVersion = version;

  // Add version header to response
  reply.header('X-API-Version', version);
}

codePatterns.deprecation:
import { FastifyRequest, FastifyReply } from 'fastify';

interface DeprecationInfo {
  endpoint: string;
  version: string;
  sunsetDate?: string;
  alternativeEndpoint?: string;
  message?: string;
}

const deprecatedEndpoints = new Map<string, DeprecationInfo>();

export function deprecate(info: DeprecationInfo) {
  return async (request: FastifyRequest, reply: FastifyReply) => {
    // Add deprecation headers
    reply.header('Deprecation', 'true');

    if (info.sunsetDate) {
      reply.header('Sunset', info.sunsetDate);
    }

    // Add warning header
    const warning = `299 - "This endpoint is deprecated${info.sunsetDate ? `. Will be removed on ${info.sunsetDate}` : ''}${info.alternativeEndpoint ? `. Use ${info.alternativeEndpoint} instead` : ''}"`;
    reply.header('Warning', warning);

    // Log deprecation usage
    request.log.warn({
      deprecation: info,
      url: request.url,
      method: request.method
    }, 'Deprecated endpoint accessed');
  };
}

// Usage:
// fastify.get('/api/v1/old-endpoint',
//   { onRequest: [deprecate({
//     endpoint: '/api/v1/old-endpoint',
//     version: 'v1',
//     sunsetDate: '2025-12-31',
//     alternativeEndpoint: '/api/v2/new-endpoint'
//   })] },
//   handler
// );

