// Filter sensitive data from logs
const SENSITIVE_FIELDS = ['password', 'token', 'secret', 'apiKey', 'authorization'];

export function sanitizeForLogging(obj: any): any {
  if (typeof obj !== 'object' || obj === null) {
    return obj;
  }

  const sanitized: any = Array.isArray(obj) ? [] : {};

  for (const [key, value] of Object.entries(obj)) {
    if (SENSITIVE_FIELDS.some(field => key.toLowerCase().includes(field))) {
      sanitized[key] = '[REDACTED]';
    } else if (typeof value === 'object') {
      sanitized[key] = sanitizeForLogging(value);
    } else {
      sanitized[key] = value;
    }
  }

  return sanitized;
}

codePatterns.sanitizer:
import { FastifyRequest, FastifyReply } from 'fastify';
import DOMPurify from 'isomorphic-dompurify';

export interface SanitizationOptions {
  body?: boolean;
  query?: boolean;
  params?: boolean;
  allowedTags?: string[];
  allowedAttributes?: string[];
}

export function sanitize(options: SanitizationOptions = {}) {
  const {
    body = true,
    query = true,
    params = true,
    allowedTags = [],
    allowedAttributes = []
  } = options;

  return async (request: FastifyRequest, reply: FastifyReply) => {
    if (body && request.body) {
      request.body = sanitizeObject(request.body, allowedTags, allowedAttributes);
    }

    if (query && request.query) {
      request.query = sanitizeObject(request.query, allowedTags, allowedAttributes);
    }

    if (params && request.params) {
      request.params = sanitizeObject(request.params, allowedTags, allowedAttributes);
    }
  };
}

function sanitizeObject(
  obj: any,
  allowedTags: string[],
  allowedAttributes: string[]
): any {
  if (typeof obj === 'string') {
    return DOMPurify.sanitize(obj, {
      ALLOWED_TAGS: allowedTags,
      ALLOWED_ATTR: allowedAttributes
    });
  }

  if (Array.isArray(obj)) {
    return obj.map(item => sanitizeObject(item, allowedTags, allowedAttributes));
  }

  if (typeof obj === 'object' && obj !== null) {
    const sanitized: any = {};
    for (const [key, value] of Object.entries(obj)) {
      sanitized[key] = sanitizeObject(value, allowedTags, allowedAttributes);
    }
    return sanitized;
  }

  return obj;
}

codePatterns.sqlInjectionPrevention:
// Prisma already prevents SQL injection, but add extra layer
export function escapeSQL(input: string): string {
  return input.replace(/[\x00\x08\x09\x1a\n\r"'\\%]/g, char => {
    switch (char) {
      case '\x00': return '\\0';
      case '\x08': return '\\b';
      case '\x09': return '\\t';
      case '\x1a': return '\\z';
      case '\n': return '\\n';
      case '\r': return '\\r';
      case '"':
      case "'":
      case '\\':
      case '%':
        return '\\' + char;
      default:
        return char;
    }
  });
}

