import { FastifyInstance } from 'fastify';
import { validate } from '../middleware/validate.js';
import { NotFoundError, InsufficientCreditsError } from '../errors/index.js';
import { createDocumentSchema } from '../schemas/document.schemas.js';

export async function documentRoutes(fastify: FastifyInstance) {
  fastify.post('/documents',
    {
      onRequest: [
        fastify.authenticate,
        validate({ body: createDocumentSchema })
      ]
    },
    async (request, reply) => {
      const { title, content, caseId } = request.body;
      const userId = request.user.id;

      // Check user credits
      const user = await fastify.prisma.user.findUnique({
        where: { id: userId }
      });

      if (!user) {
        throw new NotFoundError('User', userId);
      }

      if (user.credits < 10) {
        throw new InsufficientCreditsError(10, user.credits);
      }

      // Create document
      const document = await fastify.prisma.document.create({
        data: { title, content, userId, caseId }
      });

      return reply.code(201).send({ document });
    }
  );
}

